func (s *ServerPool) BackendCount() int {
    return len(s.backends)
}

func (s *ServerPool) GetBackend(index int) *Backend {
    return s.backends[index]
}

func main() {
    pool := &ServerPool{}
    for _, u := range []string{"http://localhost:8081", "http://localhost:8082", "http://localhost:8083"} {
        b, _ := NewBackend(u)
        pool.AddBackend(b)
    }
    for i := 0; i < pool.BackendCount(); i++ {
        fmt.Println(pool.GetBackend(i).URL.Host)
    }
}
