The code below has a subtle bug: `AddBackend` doesn't modify the original pool. Identify the bug and fix it.

```go
type ServerPool struct {
    backends []*Backend
    current  uint64
}

func (s ServerPool) AddBackend(b *Backend) {
    s.backends = append(s.backends, b)
}

func main() {
    pool := ServerPool{}
    b, _ := NewBackend("http://localhost:8080")
    pool.AddBackend(b)
    fmt.Println(len(pool.backends)) // prints 0, not 1
}
```
